mapper.select:
SELECT A.*, (SELECT COUNT(*) FROM meetup_applications WHERE meetup_id = a.meetup_id AND status = 'APPROVED' AND A.delete_yn = 'n' ) AS total_participants, B.nickname FROM meetups AS A LEFT OUTER JOIN members AS B ON B.member_id = A.member_id WHERE A.delete_yn = 'N' AND A.status != 'DELETED'
AND A.status = #{status}
AND A.title LIKE CONCAT('%', #{searchText}, '%')
AND B.nickname LIKE CONCAT('%', #{searchText}, '%')
ORDER BY A.created_at DESC LIMIT #{start}, #{end}

